public int rob(int[] nums) {
    int prev2=0, prev1=0;
    for (int num : nums) {
        int cur = Math.max(prev1, prev2+num);
        prev2=prev1; prev1=cur;
    }
    return prev1;
}

public int lengthOfLIS(int[] nums) {
    List<Integer> tails = new ArrayList<>();
    for (int num : nums) {
        int lo=0, hi=tails.size();
        while (lo<hi) {
            int mid=lo+(hi-lo)/2;
            if (tails.get(mid)<num) lo=mid+1;
            else hi=mid;
        }
        if (lo==tails.size()) tails.add(num);
        else tails.set(lo, num);
    }
    return tails.size();
}

public int coinChange(int[] coins, int amount) {
    int[] dp = new int[amount+1];
    Arrays.fill(dp, amount+1);
    dp[0]=0;
    for (int i=1;i<=amount;i++)
        for (int c:coins)
            if (c<=i) dp[i]=Math.min(dp[i], dp[i-c]+1);
    return dp[amount]>amount ? -1 : dp[amount];
}

public int minDistance(String w1, String w2) {
    int m=w1.length(), n=w2.length();
    int[][] dp = new int[m+1][n+1];
    for (int i=0;i<=m;i++) dp[i][0]=i;
    for (int j=0;j<=n;j++) dp[0][j]=j;
    for (int i=1;i<=m;i++)
        for (int j=1;j<=n;j++) {
            if (w1.charAt(i-1)==w2.charAt(j-1)) dp[i][j]=dp[i-1][j-1];
            else dp[i][j]=1+Math.min(dp[i-1][j-1], Math.min(dp[i-1][j], dp[i][j-1]));
        }
    return dp[m][n];
}

public List<List<Integer>> permute(int[] nums) {
    List<List<Integer>> res = new ArrayList<>();
    backtrack(nums, new boolean[nums.length], new ArrayList<>(), res);
    return res;
}
void backtrack(int[] nums, boolean[] used, List<Integer> path, List<List<Integer>> res) {
    if (path.size()==nums.length) { res.add(new ArrayList<>(path)); return; }
    for (int i=0;i<nums.length;i++) {
        if (used[i]) continue;
        used[i]=true; path.add(nums[i]);
        backtrack(nums, used, path, res);
        used[i]=false; path.remove(path.size()-1);
    }
}

public List<List<Integer>> subsets(int[] nums) {
    List<List<Integer>> res = new ArrayList<>();
    backtrack(nums, 0, new ArrayList<>(), res);
    return res;
}
void backtrack(int[] nums, int start, List<Integer> path, List<List<Integer>> res) {
    res.add(new ArrayList<>(path));
    for (int i=start;i<nums.length;i++) {
        path.add(nums[i]);
        backtrack(nums, i+1, path, res);
        path.remove(path.size()-1);
    }
}

public List<List<Integer>> combinationSum(int[] candidates, int target) {
    List<List<Integer>> res = new ArrayList<>();
    Arrays.sort(candidates);
    backtrack(candidates, target, 0, new ArrayList<>(), res);
    return res;
}
void backtrack(int[] c, int remain, int start, List<Integer> path, List<List<Integer>> res) {
    if (remain==0) { res.add(new ArrayList<>(path)); return; }
    for (int i=start;i<c.length;i++) {
        if (c[i]>remain) break;
        path.add(c[i]);
        backtrack(c, remain-c[i], i, path, res);
        path.remove(path.size()-1);
    }
}

public List<List<String>> solveNQueens(int n) {
    List<List<String>> res = new ArrayList<>();
    Set<Integer> cols=new HashSet<>(), d1=new HashSet<>(), d2=new HashSet<>();
    backtrack(n, 0, new int[n], cols, d1, d2, res);
    return res;
}
void backtrack(int n, int row, int[] queens, Set<Integer> cols, Set<Integer> d1, Set<Integer> d2, List<List<String>> res) {
    if (row==n) { res.add(build(queens,n)); return; }
    for (int col=0;col<n;col++) {
        if (cols.contains(col)||d1.contains(row-col)||d2.contains(row+col)) continue;
        queens[row]=col; cols.add(col); d1.add(row-col); d2.add(row+col);
        backtrack(n, row+1, queens, cols, d1, d2, res);
        cols.remove(col); d1.remove(row-col); d2.remove(row+col);
    }
}
List<String> build(int[] queens, int n) {
    List<String> board=new ArrayList<>();
    for (int q:queens) {
        char[] row=new char[n]; Arrays.fill(row,'.'); row[q]='Q';
        board.add(new String(row));
    }
    return board;
}

public boolean exist(char[][] board, String word) {
    for (int i=0;i<board.length;i++)
        for (int j=0;j<board[0].length;j++)
            if (dfs(board,word,i,j,0)) return true;
    return false;
}
boolean dfs(char[][] b, String w, int i, int j, int k) {
    if (k==w.length()) return true;
    if (i<0||i>=b.length||j<0||j>=b[0].length||b[i][j]!=w.charAt(k)) return false;
    char tmp=b[i][j]; b[i][j]='#';
    boolean found=dfs(b,w,i+1,j,k+1)||dfs(b,w,i-1,j,k+1)||dfs(b,w,i,j+1,k+1)||dfs(b,w,i,j-1,k+1);
    b[i][j]=tmp;
    return found;
}

public boolean canJump(int[] nums) {
    int maxReach = 0;
    for (int i=0; i<nums.length; i++) {
        if (i > maxReach) return false;
        maxReach = Math.max(maxReach, i+nums[i]);
    }
    return true;
}

public int canCompleteCircuit(int[] gas, int[] cost) {
    int total=0, tank=0, start=0;
    for (int i=0; i<gas.length; i++) {
        int diff = gas[i]-cost[i];
        total+=diff; tank+=diff;
        if (tank < 0) { start=i+1; tank=0; }
    }
    return total>=0 ? start : -1;
}

public int leastInterval(char[] tasks, int n) {
    int[] freq = new int[26];
    for (char t : tasks) freq[t-'A']++;
    Arrays.sort(freq);
    int maxFreq = freq[25];
    int maxCount = 0;
    for (int f : freq) if (f==maxFreq) maxCount++;
    return Math.max(tasks.length, (maxFreq-1)*(n+1)+maxCount);
}

public int eraseOverlapIntervals(int[][] intervals) {
    Arrays.sort(intervals, (a,b)->a[1]-b[1]);
    int end=intervals[0][1], count=0;
    for (int i=1;i<intervals.length;i++) {
        if (intervals[i][0] < end) count++;
        else end=intervals[i][1];
    }
    return count;
}

public List<Integer> partitionLabels(String s) {
    int[] last = new int[26];
    for (int i=0;i<s.length();i++) last[s.charAt(i)-'a']=i;
    List<Integer> res = new ArrayList<>();
    int start=0, end=0;
    for (int i=0;i<s.length();i++) {
        end=Math.max(end, last[s.charAt(i)-'a']);
        if (i==end) { res.add(end-start+1); start=i+1; }
    }
    return res;
}
